svg.script:

// Generate 50 random ambient particles
window.addEventListener('load', function() {
  const g = document.getElementById('particles');
  const colors = ['#FF5B35', '#4F9EFF', '#FFD700', '#FFFFFF', '#34D399'];
  for (let i = 0; i < 50; i++) {
    const c = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
    c.setAttribute('cx', Math.random() * 1280);
    c.setAttribute('cy', Math.random() * 340);
    c.setAttribute('r', Math.random() * 1.2 + 0.3);
    c.setAttribute('fill', colors[Math.floor(Math.random() * colors.length)]);
    c.style.animationDuration = (Math.random() * 6 + 4) + 's';
    c.style.animationDelay = (Math.random() * 5) + 's';
    c.classList.add('particle');
    g.appendChild(c);
  }
});

// Mouse-reactive parallax on ambient glows
document.addEventListener('mousemove', function(e) {
  const svg = document.querySelector('svg');
  const pt = svg.createSVGPoint();
  pt.x = e.clientX; pt.y = e.clientY;
  const loc = pt.matrixTransform(svg.getScreenCTM().inverse());
  const mx = loc.x / 1280;
  const my = loc.y / 340;

  const ember = document.getElementById('emberGlow');
  const blue = document.getElementById('blueGlow');
  if (ember) {
    ember.setAttribute('cx', (15 + mx * 10) + '%');
    ember.setAttribute('cy', (55 + my * 10) + '%');
  }
  if (blue) {
    blue.setAttribute('cx', (85 - mx * 10) + '%');
    blue.setAttribute('cy', (35 - my * 10) + '%');
  }
});
